(function(){"use strict";document.querySelectorAll('.entry-content iframe[src*="youtube"], .entry-content iframe[src*="vimeo"]').forEach(function(e){if(!e.parentElement.classList.contains("embed-responsive")){var t=document.createElement("div");t.className="embed-responsive",e.parentNode.insertBefore(t,e),t.appendChild(e)}}),document.querySelectorAll('a[href^="#"]:not([href="#"])').forEach(function(e){e.addEventListener("click",function(t){var n=document.querySelector(this.getAttribute("href"));n&&(t.preventDefault(),n.scrollIntoView({behavior:"smooth",block:"start"}),history.pushState(null,null,this.getAttribute("href")))})}),document.addEventListener("keydown",function(e){e.key==="Tab"&&document.body.classList.add("using-keyboard")}),document.addEventListener("mousedown",function(){document.body.classList.remove("using-keyboard")})})();
